mapper.select:
select ply.id as rowId,ply.title as title, ply.data_status as dataStatus,ply.sub_date as subDate,
suser.name as subUserName,ply.contribute_date as sendDate,
fuser.name as firstAuthorName,cuser.name as corrAuthorName,fdept.name as firstAuthorName,
cdept.name as corrAuthorName,fdept.name as firstAuthorDeptName,cdept.name as corrAuthorDeptName,createuser.name as creatorName
from srm_paper_submission_apply ply
left join ct_srm_user suser on suser.id=ply.sub_user_id
left join ct_srm_user fuser on fuser.id=ply.first_author_id
left join ct_srm_user cuser on cuser.id=ply.corr_author_id
left join ct_srm_user createuser on createuser.id=ply.creator
left join ct_srm_dept fdept on fdept.id=ply.first_author_dept_id
left join ct_srm_dept cdept on cdept.id=ply.corr_author_dept_id
where (ply.creator=#{paperSubmissionApplyDto.userId}
    or ply.sub_user_id=#{paperSubmissionApplyDto.userId}
    or ply.first_author_id=#{paperSubmissionApplyDto.userId}
    or ply.corr_author_id=#{paperSubmissionApplyDto.userId})

    and ply.title like CONCAT('%', #{paperSubmissionApplyDto.title}, '%')


    and ply.first_author_id=#{paperSubmissionApplyDto.firstAuthor}


    and ply.sub_date >= #{paperSubmissionApplyDto.startDate}


    and ply.sub_date <= #{paperSubmissionApplyDto.endDate}


    and ply.journal=#{paperSubmissionApplyDto.journal}


    and ply.data_status = #{paperSubmissionApplyDto.dataStatus}

order by ply.id desc

select ply.id as rowId,ply.title as title, ply.data_status as dataStatus,ply.sub_date as subDate, suser.name as subUserName,ply.contribute_date as sendDate, fuser.name as firstAuthorName,cuser.name as corrAuthorName, fdept.name as firstAuthorDeptName,cdept.name as corrAuthorDeptName,createuser.name as creatorName from srm_paper_submission_apply ply left join ct_srm_user suser on suser.id=ply.sub_user_id left join ct_srm_user createuser on createuser.id=ply.creator left join ct_srm_user fuser on fuser.id=ply.first_author_id left join ct_srm_user cuser on cuser.id=ply.corr_author_id left join ct_srm_dept fdept on fdept.id=ply.first_author_dept_id left join ct_srm_dept cdept on cdept.id=ply.corr_author_dept_id left join cf_srm_eaf_rec eafrec on eafrec.sys_no=ply.sys_no and eafrec.check_rec_id=ply.id where eafrec.step_no>1
and ((ply.data_status=1 and eafrec.is_current_step=1 and eafrec.checker_string LIKE CONCAT('%|', #{paperSubmissionApplyDto.userId}, '|%')) or (eafrec.step_no = (select max(step_no) from cf_srm_eaf_rec seafrec where ply.sys_no=seafrec.sys_no and seafrec.check_rec_id=ply.id) and eafrec.checker_string LIKE CONCAT('%|', #{paperSubmissionApplyDto.userId}, '|%') and eafrec.check_datetime is not null) or (ply.data_status=0 and eafrec.is_current_step=1 and eafrec.check_result=3 and eafrec.checker_string LIKE CONCAT('%|', #{paperSubmissionApplyDto.userId}, '|%')) )
and ply.data_status=1 and eafrec.is_current_step=1 and eafrec.checker_string LIKE CONCAT('%|', #{paperSubmissionApplyDto.userId}, '|%')
and ply.data_status=1 and eafrec.check_result="2" and eafrec.checker_string LIKE CONCAT('%|', #{paperSubmissionApplyDto.userId}, '|%')
and ply.data_status=0 and eafrec.check_result="3" and eafrec.checker_string LIKE CONCAT('%|', #{paperSubmissionApplyDto.userId}, '|%')
and ply.title like CONCAT('%', #{paperSubmissionApplyDto.title}, '%')
and ply.first_author_id=#{paperSubmissionApplyDto.firstAuthor}
and ply.sub_date >= #{paperSubmissionApplyDto.startDate}
and ply.sub_date <= #{paperSubmissionApplyDto.endDate}
and ply.journal=#{paperSubmissionApplyDto.journal}

select spsg.id as rowId, ply.title as title,spsg.app_rowId as appRowId,spsg.note as note, csu.name as subUserName, ply.sub_date as subDate , fuser.name as firstAuthorName,cuser.name as corrAuthorName, fdept.name as firstAuthorDeptName,cdept.name as corrAuthorDeptName, spsg.audit_status as auditStatus,spsg.data_status as dataStatus from srm_paper_submission_grade spsg left join srm_paper_submission_apply ply on ply.id=spsg.app_rowId left join ct_srm_user csu on csu.id=ply.sub_user_id left join ct_srm_user fuser on fuser.id=ply.first_author_id left join ct_srm_user cuser on cuser.id=ply.corr_author_id left join ct_srm_dept fdept on fdept.id=ply.first_author_dept_id left join ct_srm_dept cdept on cdept.id=ply.corr_author_dept_id
where spsg.expert=#{paperSubmissionExpertAuditDto.userId} and spsg.sys_no=#{paperSubmissionExpertAuditDto.sysNo}
and ply.title=#{paperSubmissionExpertAuditDto.title}
